import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { casesData } from '../data/cases';
import OpeningAnimation from '../components/OpeningAnimation';

const CaseDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const caseItem = casesData.find(c => c.id === Number(id));

  const [opening, setOpening] = useState(false);
  const [result, setResult] = useState<string | null>(null);

  if (!caseItem) {
    return <div>Кейс не найден</div>;
  }

  const startOpening = () => {
    setOpening(true);
    // Имитация запроса к бэкенду
    setTimeout(() => {
      // 90% шанс на сгенерированный ключ
      const isReal = Math.random() < 0.1; // 10% реальный
      let key = '';
      if (isReal) {
        // Здесь должен быть запрос к админке, пока заглушка
        key = 'AAAAA-BBBBB-CCCCC-DDDDD-EEEEE-REAL';
      } else {
        // Генерация ключа
        const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
        const segment = () => Array(5).fill(0).map(() => chars[Math.floor(Math.random() * chars.length)]).join('');
        key = `${segment()}-${segment()}-${segment()}-${segment()}-${segment()}`;
      }
      setResult(key);
      setOpening(false);
    }, 3000);
  };

  const reset = () => {
    setResult(null);
  };

  return (
    <div className="case-detail">
      <AnimatePresence mode="wait">
        {opening ? (
          <OpeningAnimation isOpening={true} result={null} />
        ) : result ? (
          <motion.div
            key="result"
            initial={{ scale: 0.8, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            className="result-box"
          >
            <h2>🎉 Ваш ключ</h2>
            <div className="key-display">{result}</div>
            <p className="key-note">Ключ можно активировать в Steam</p>
            <button onClick={reset} className="back-button">Закрыть</button>
          </motion.div>
        ) : (
          <motion.div
            key="info"
            initial={{ x: -50, opacity: 0 }}
            animate={{ x: 0, opacity: 1 }}
            className="case-info"
          >
            <h1>{caseItem.name}</h1>
            <p className="price">Цена: ⭐ {caseItem.price_stars}</p>
            <button onClick={startOpening} className="open-button">Открыть кейс</button>
            <button onClick={() => navigate('/market')} className="back-button">Назад в маркет</button>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default CaseDetail;
